import{_ as a,c as e,o as s,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"고급 구성: 고급 기능 상세 설명 | Antigravity-Manager","description":"Antigravity-Manager의 고급 구성 방법을 학습합니다. 계정 스케줄링, 모델 라우팅, 쿼터 거버넌스 및 모니터링 통계 등 고급 기능을 마스터합니다.","frontmatter":{"title":"고급 구성: 고급 기능 상세 설명 | Antigravity-Manager","order":300,"sidebarTitle":"시스템을 프로덕션 레벨로 업그레이드","subtitle":"고급 구성: 고급 기능 상세 설명","description":"Antigravity-Manager의 고급 구성 방법을 학습합니다. 계정 스케줄링, 모델 라우팅, 쿼터 거버넌스 및 모니터링 통계 등 고급 기능을 마스터합니다."},"headers":[],"relativePath":"ko/lbjlaq/Antigravity-Manager/advanced/index.md","filePath":"ko/lbjlaq/Antigravity-Manager/advanced/index.md"}'),n={name:"ko/lbjlaq/Antigravity-Manager/advanced/index.md"};function d(o,t,i,l,p,c){return s(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="고급-구성" tabindex="-1">고급 구성 <a class="header-anchor" href="#고급-구성" aria-label="Permalink to &quot;고급 구성&quot;">​</a></h1><p>이 장에서는 Antigravity Tools의 고급 기능을 심층적으로 설명합니다: 구성 관리, 보안 정책, 계정 스케줄링, 모델 라우팅, 쿼터 거버넌스, 모니터링 통계, 및 서버 배포 방안. 이 내용을 마스터한 후에는 Antigravity Tools를 &quot;사용 가능&quot;에서 &quot;사용하기 쉽고, 안정적이며, 운영 가능&quot;으로 업그레이드할 수 있습니다.</p><h2 id="이-장-포함" tabindex="-1">이 장 포함 <a class="header-anchor" href="#이-장-포함" aria-label="Permalink to &quot;이 장 포함&quot;">​</a></h2><table tabindex="0"><thead><tr><th>튜토리얼</th><th>설명</th></tr></thead><tbody><tr><td><a href="./config/">설정 완벽 가이드</a></td><td>AppConfig/ProxyConfig의 완전 필드, 저장 위치 및 핫 리로드 의미</td></tr><tr><td><a href="./security/">보안 및 프라이버시</a></td><td><code>auth_mode</code>, <code>allow_lan_access</code> 및 보안 기선 설계</td></tr><tr><td><a href="./scheduling/">고가용성 스케줄링</a></td><td>로테이션, 고정 계정, 스티키 세션 및 실패 재시도 메커니즘</td></tr><tr><td><a href="./model-router/">모델 라우팅</a></td><td>커스텀 매핑, 와일드카드 우선순위 및 프리셋 전략</td></tr><tr><td><a href="./quota/">쿼터 거버넌스</a></td><td>Quota Protection + Smart Warmup의 조합 전술</td></tr><tr><td><a href="./monitoring/">Proxy Monitor</a></td><td>요청 로그, 필터링, 상세 복원 및 내보내기</td></tr><tr><td><a href="./token-stats/">Token Stats</a></td><td>비용 관점의 통계 지표 및 차트 해석</td></tr><tr><td><a href="./context-compression/">긴 세션 안정성</a></td><td>컨텍스트 압축, 서명 캐시 및 툴 결과 압축</td></tr><tr><td><a href="./system/">시스템 능력</a></td><td>다국어/테마/업데이트/시작 자동 시작/HTTP API Server</td></tr><tr><td><a href="./deployment/">서버 배포</a></td><td>Docker noVNC vs Headless Xvfb 선형 및 운영</td></tr></tbody></table><h2 id="학습-경로-제안" tabindex="-1">학습 경로 제안 <a class="header-anchor" href="#학습-경로-제안" aria-label="Permalink to &quot;학습 경로 제안&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">추천 순서</p><p>이 장의 내용이 많으므로, 다음과 같이 모듈별로 배치 학습하는 것이 좋습니다:</p></div><p><strong>첫 번째 단계: 구성 및 보안(필수)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>설정 완벽 가이드 → 보안 및 프라이버시</span></span>
<span class="line"><span>config      security</span></span></code></pre></div><p>먼저 구성 시스템을 이해하고(어떤 것이 재시작이 필요하고, 어떤 것이 핫 리로드되는지), 다음 보안 설정을 학습하세요(특히 LAN/공개 네트워크에 노출할 때).</p><p><strong>두 번째 단계: 스케줄링 및 라우팅(추천)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>고가용성 스케줄링 → 모델 라우팅</span></span>
<span class="line"><span>scheduling    model-router</span></span></code></pre></div><p>최소 계정 수로 최대 안정성을 얻는 방법을 배우고, 다음 모델 라우팅으로 업스트림 변화를 차단하세요.</p><p><strong>세 번째 단계: 쿼터 및 모니터링(필요에 따라)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>쿼터 거버넌스 → Proxy Monitor → Token Stats</span></span>
<span class="line"><span>quota        monitoring      token-stats</span></span></code></pre></div><p>쿼터가 무의식적으로 소진되는 것을 방지하고, 호출 블랙박스를 관찰 가능한 시스템으로 만들고, 비용 최적화를 정량화합니다.</p><p><strong>네 번째 단계: 안정성 및 배포(고급)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>긴 세션 안정성 → 시스템 능력 → 서버 배포</span></span>
<span class="line"><span>context-compression  system    deployment</span></span></code></pre></div><p>긴 세션의 은닉적 문제를 해결하고, 클라이언트를 더 제품처럼 만들고, 마지막으로 서버 배포를 학습합니다.</p><p><strong>빠른 선택</strong>:</p><table tabindex="0"><thead><tr><th>시나리오</th><th>먼저 볼 것 추천</th></tr></thead><tbody><tr><td>다중 계정 로테이션이 불안정함</td><td><a href="./scheduling/">고가용성 스케줄링</a></td></tr><tr><td>특정 모델 이름을 고정하고 싶음</td><td><a href="./model-router/">모델 라우팅</a></td></tr><tr><td>쿼터가 항상 다 소진됨</td><td><a href="./quota/">쿼터 거버넌스</a></td></tr><tr><td>요청 로그를 보고 싶음</td><td><a href="./monitoring/">Proxy Monitor</a></td></tr><tr><td>토큰 소비를 통계하고 싶음</td><td><a href="./token-stats/">Token Stats</a></td></tr><tr><td>긴 대화가 자주 오류 발생</td><td><a href="./context-compression/">긴 세션 안정성</a></td></tr><tr><td>LAN에 노출하려고 함</td><td><a href="./security/">보안 및 프라이버시</a></td></tr><tr><td>서버에 배포하려고 함</td><td><a href="./deployment/">서버 배포</a></td></tr></tbody></table><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">시작 전 확인</p><ul><li><a href="./../start/">빠른 시작</a> 장을 완료했습니다(최소 설치, 계정 추가, 리버스 프록시 시작 완료)</li><li><a href="./../platforms/">플랫폼 및 통합</a>에서 최소 하나의 프로토콜 접속을 완료했습니다(예: OpenAI 또는 Anthropic)</li><li>로컬 리버스 프록시가 요청에 정상적으로 응답할 수 있습니다</li></ul></div><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장을 학습한 후, 계속 학습할 수 있습니다:</p><ul><li><a href="./../faq/">일반적인 질문</a>: 401/404/429/스트리밍 중단 등 문제 발생 시 문제 해결 가이드</li><li><a href="./../appendix/">부록</a>: 엔드포인트 빠른 참조표, 데이터 모델, z.ai 능력 경계 등 참조 자료</li></ul>`,25)])])}const g=a(n,[["render",d]]);export{u as __pageData,g as default};
